DROP TABLE IF EXISTS `clinics`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `clinics` (
  `id` int NOT NULL AUTO_INCREMENT,
  `clinic_name` varchar(150) NOT NULL,
  `email` varchar(150) NOT NULL,
  `phone` varchar(20) NOT NULL,
  `province_id` int NOT NULL,
  `municipality_id` int NOT NULL,
  `barangay_id` int NOT NULL,
  `address` varchar(255) NOT NULL,
  `specialization` varchar(150) NOT NULL,
  `license_number` varchar(100) NOT NULL,
  `years_operation` int DEFAULT NULL,
  `rep_full_name` varchar(150) NOT NULL,
  `rep_position` varchar(100) NOT NULL,
  `rep_phone` varchar(20) NOT NULL,
  `services_offered` varchar(150) NOT NULL,
  `opening_time` time NOT NULL,
  `closing_time` time NOT NULL,
  `operating_days` varchar(100) NOT NULL,
  `clinic_license_file` varchar(255) DEFAULT NULL,
  `rep_valid_id_file` varchar(255) DEFAULT NULL,
  `password_hash` varchar(255) NOT NULL,
  `status` enum('pending','approved','rejected') NOT NULL DEFAULT 'pending',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `email` (`email`),
  UNIQUE KEY `license_number` (`license_number`),
  KEY `fk_clinic_province` (`province_id`),
  KEY `fk_clinic_municipality` (`municipality_id`),
  KEY `fk_clinic_barangay` (`barangay_id`),
  CONSTRAINT `fk_clinic_barangay` FOREIGN KEY (`barangay_id`) REFERENCES `barangays` (`id`),
  CONSTRAINT `fk_clinic_municipality` FOREIGN KEY (`municipality_id`) REFERENCES `municipalities` (`id`),
  CONSTRAINT `fk_clinic_province` FOREIGN KEY (`province_id`) REFERENCES `provinces` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
